update public.products set mrp = 3765, brand_sku = 'WHFFFNYA11X0', image_url = 'https://havells.com/media/catalog/product/cache/74c1057f7991b4edb2bc7bdaa94de933/import/flexible_cables/life_guard/90m/yellow.jpg', tech_specs = '{"source":"havells.com","description":"Shop for the Havells WHFFFNKA11X0-C flexible cable, designed for reliable electrical performance. Ideal for various applications, offering superior flexibility and durability.","key_features":["Application : Energy Cables for Internal electrification and power Supply to all electrical operated equipments (eg. Fans/Lights/ Aplliances etc).","Type : FRLSH PVC Flexible Cables upto 1.1 kV grade as per IS:694","Size : 1.0 sq. mm to 6 sq. mm in Single core and for above sizes in S/C and Multi Core Sizes on request."],"features":[{"title":"High Oxygen Index","body":"The oxygen index is 30% for FRLSH insulation .i.e. the Havells FRLSH insulation can catch the flame only if oxygen level in atmosphere or air is more than 30% whereas it known fact that in atmosphere oxygen level is 21% only. Higher the index value, greater the non-combustibility."}],"specs":{"Manufactured By":"Havells India Ltd","Country Of Origin":"India","Core":"Single Core","Size":"1.0 sq. mm","Type":"Flame Retardant Low Smoke Halogen","Net Quantity":"1 N","Product range":"Life Guard (FR-LSH)"}}'::jsonb || coalesce(tech_specs, '{}'::jsonb) where id = 'wire-havells-frlsh-1-yellow';
update public.products set tech_specs = '{"source":"havells.com","description":"Discover the Lifeline HRFR Flexible Cable from Havells. Ideal for electrical installations with high performance and safety features. Buy now for reliable and durable wiring solutions.","key_features":["Application : Energy Cables for Internal electrification and power Supply to all electrical operated equipments (eg. Fans/Lights/ Aplliances etc).","Type : HRFR PVC Flexible Cables upto 1.1 kV grade as per IS:694","Size : 0.5 sq. mm to 6 sq. mm in Single core and for above sizes in S/C and Multi Core Sizes on request."],"features":[{"title":"Heat Resistance Flame Retardant","body":"Current carrying capacity of a wire is defined as how much load a conductor can carry (In amperage). When the current flows through the conductor a certain level of heat generates which can further increase up to the melting temperature of the insulation or insulating material. Havells wires offer insulation with (HR) Heat resistant along with Flame Retardant properties which are suitable to bear a temperature up to 85 °C whereas ordinary PVC is suitable only up to 70 °C and due to this feature HAVELLS Wires are capable to carry Higher current and ensures better electrical and mechanical performance at higher temperatures. The HRFR property is available from 0.5 sq. mm to 630 sq. mm in single core."},{"title":"High Insulation Resistance","body":"In all cables, there is generally leakage of current from the live conductor through the insulation. In case of inferior quality of insulation, the current leakage increases. This is unsafe and can cause damage to installations as well as become a threat to life. Low Leakage Current – Havells wires have an allowable current-leakage limit that is 50 times lower than the prescribed international safety norms. safety standards specifies that current leakage limit in hand held equipment is considered to be safe if the value is not more than 0.75 mA. Havells cables, with S3 technology, incorporate insulation of high quality which ensures that current leakage level is as low as 0.01 mA, which is much below the prescribed limit. Havells cables have been certified by the Central Power and Research Institute (CPRI) - a premier laboratory recognised by the Government of India. Safety from electrical shocks – Electric shock occurs when a body-part comes in contact with a bare conductor of poor insulated wire. Higher insulation resistance protects against electric shock."},{"title":"RoHS Compliant","body":"Release of certain harmful substances such as lead, mercury, cadmium and chromium etc. in the plastics/equipment are dangerous to the environment and health. European Union has adopted a directive on the restriction of the use of certain hazardous substances in electrical and electronics equipment commonly referred to as Restriction of Hazardous Substances directive or RoHS. cables with S3 technology are certified by Bureau Veritas for RoHS compliance as per directive 2006/95/EC. This ensures that release of hazardous substances are eliminated to provide safety for human health and to give us green environment. initiative for eco friendly environment by Havells."},{"title":"Anti Termite and Rodent","body":"Termites and rodents cause extensive damage to paper, wood, plastic etc. In case of electrical installation, damaged caused by above pests may lead to short circuit which can become a cause for a major disaster, loss of property and human life. Havells cables with S3 technology provide insulation with termite and rodent repulsion properties. Certification regarding the above has been obtained from the Central Power and Research Institute (CPRI). Anti termite/Anti rodent feature is applicable for a period of 12 months from the date of invoice."},{"title":"Best Copper Used","body":"Havells wire use ETP grade annealed copper which is more than 99.95% pure and therefore ensures 101% conductivity (IACS)."}],"specs":{"Manufactured By":"Havells India Ltd","Country Of Origin":"India","Core":"Single Core","Size":"1.5 sq. mm","Type":"Heat Resistant Flame Retardant","Net Quantity":"1 N","Product range":"Lifeline Plus S3 (HRFR)"}}'::jsonb || coalesce(tech_specs, '{}'::jsonb) where id = 'hav-ll-15';
update public.products set brand_sku = 'WHFFDNKA11X5', image_url = 'https://havells.com/media/catalog/product/cache/74c1057f7991b4edb2bc7bdaa94de933/import/Flexible-Cables/WHFFDNKA11X5.jpg', tech_specs = '{"source":"havells.com","description":"Discover the Lifeline HRFR Flexible Cable from Havells. Ideal for electrical installations with high performance and safety features. Buy now for reliable and durable wiring solutions.","key_features":["Application : Energy Cables for Internal electrification and power Supply to all electrical operated equipments (eg. Fans/Lights/ Aplliances etc).","Type : HRFR PVC Flexible Cables upto 1.1 kV grade as per IS:694","Size : 0.5 sq. mm to 6 sq. mm in Single core and for above sizes in S/C and Multi Core Sizes on request."],"features":[{"title":"Heat Resistance Flame Retardant","body":"Current carrying capacity of a wire is defined as how much load a conductor can carry (In amperage). When the current flows through the conductor a certain level of heat generates which can further increase up to the melting temperature of the insulation or insulating material. Havells wires offer insulation with (HR) Heat resistant along with Flame Retardant properties which are suitable to bear a temperature up to 85 °C whereas ordinary PVC is suitable only up to 70 °C and due to this feature HAVELLS Wires are capable to carry Higher current and ensures better electrical and mechanical performance at higher temperatures. The HRFR property is available from 0.5 sq. mm to 630 sq. mm in single core."},{"title":"High Insulation Resistance","body":"In all cables, there is generally leakage of current from the live conductor through the insulation. In case of inferior quality of insulation, the current leakage increases. This is unsafe and can cause damage to installations as well as become a threat to life. Low Leakage Current – Havells wires have an allowable current-leakage limit that is 50 times lower than the prescribed international safety norms. safety standards specifies that current leakage limit in hand held equipment is considered to be safe if the value is not more than 0.75 mA. Havells cables, with S3 technology, incorporate insulation of high quality which ensures that current leakage level is as low as 0.01 mA, which is much below the prescribed limit. Havells cables have been certified by the Central Power and Research Institute (CPRI) - a premier laboratory recognised by the Government of India. Safety from electrical shocks – Electric shock occurs when a body-part comes in contact with a bare conductor of poor insulated wire. Higher insulation resistance protects against electric shock."},{"title":"RoHS Compliant","body":"Release of certain harmful substances such as lead, mercury, cadmium and chromium etc. in the plastics/equipment are dangerous to the environment and health. European Union has adopted a directive on the restriction of the use of certain hazardous substances in electrical and electronics equipment commonly referred to as Restriction of Hazardous Substances directive or RoHS. cables with S3 technology are certified by Bureau Veritas for RoHS compliance as per directive 2006/95/EC. This ensures that release of hazardous substances are eliminated to provide safety for human health and to give us green environment. initiative for eco friendly environment by Havells."},{"title":"Anti Termite and Rodent","body":"Termites and rodents cause extensive damage to paper, wood, plastic etc. In case of electrical installation, damaged caused by above pests may lead to short circuit which can become a cause for a major disaster, loss of property and human life. Havells cables with S3 technology provide insulation with termite and rodent repulsion properties. Certification regarding the above has been obtained from the Central Power and Research Institute (CPRI). Anti termite/Anti rodent feature is applicable for a period of 12 months from the date of invoice."},{"title":"Best Copper Used","body":"Havells wire use ETP grade annealed copper which is more than 99.95% pure and therefore ensures 101% conductivity (IACS)."}],"specs":{"Manufactured By":"Havells India Ltd","Country Of Origin":"India","Core":"Single Core","Size":"1.5 sq. mm","Type":"Heat Resistant Flame Retardant","Net Quantity":"1 N","Product range":"Lifeline Plus S3 (HRFR)"}}'::jsonb || coalesce(tech_specs, '{}'::jsonb) where id = 'wire-havells-hrfr-1p5-black';
